extends SceneTree

func _initialize():
    var errors = []

    # Load the scene
    var packed = load("res://scenes/Ragdoll.tscn")
    if packed == null:
        printerr("FAIL: Could not load res://scenes/Ragdoll.tscn")
        quit(1)
        return

    var root = packed.instantiate()
    if root == null:
        printerr("FAIL: Could not instantiate Ragdoll.tscn")
        quit(1)
        return

    # Check root type
    if not root is Node2D:
        errors.append("Root is not Node2D: " + root.get_class())

    # Check script
    if not root.get_script():
        errors.append("Root has no script")
    elif root.get_script().resource_path != "res://scripts/Ragdoll.gd":
        errors.append("Wrong script: " + root.get_script().resource_path)

    # Check class_name
    if not root.has_method("apply_impulse_to"):
        errors.append("Missing method: apply_impulse_to")
    if not root.has_method("freeze_all"):
        errors.append("Missing method: freeze_all")
    if not root.has_method("get_part"):
        errors.append("Missing method: get_part")
    if not root.has_method("get_average_position"):
        errors.append("Missing method: get_average_position")

    # Check signal
    if not root.has_signal("ragdoll_collapsed"):
        errors.append("Missing signal: ragdoll_collapsed")

    # Check RigidBody2D children
    var expected_parts = ["Head", "Torso", "LeftArm", "RightArm", "LeftLeg", "RightLeg"]
    var found_parts = []
    var pin_joints = []

    for child in root.get_children():
        if child is RigidBody2D:
            found_parts.append(child.name)
            # Check CollisionShape2D
            var has_collision = false
            var has_visual = false
            for grandchild in child.get_children():
                if grandchild is CollisionShape2D:
                    has_collision = true
                    if grandchild.shape == null:
                        errors.append(child.name + ".CollisionShape2D has null shape")
                if grandchild is ColorRect or grandchild is Polygon2D:
                    has_visual = true
            if not has_collision:
                errors.append(child.name + " has no CollisionShape2D")
            if not has_visual:
                errors.append(child.name + " has no visual (ColorRect or Polygon2D)")
        elif child is PinJoint2D:
            pin_joints.append(child)

    # Check part names
    for pname in expected_parts:
        if not pname in found_parts:
            errors.append("Missing RigidBody2D: " + pname)

    var extra_parts = []
    for pname in found_parts:
        if not pname in expected_parts:
            extra_parts.append(pname)
    if extra_parts.size() > 0:
        errors.append("Extra RigidBody2D parts: " + str(extra_parts))

    if found_parts.size() != 6:
        errors.append("Expected 6 RigidBody2D children, found " + str(found_parts.size()))

    # Check PinJoint2D count
    if pin_joints.size() != 5:
        errors.append("Expected 5 PinJoint2D, found " + str(pin_joints.size()))

    # Check PinJoint2D connections
    var expected_pairs = [
        ["Head", "Torso"],
        ["LeftArm", "Torso"],
        ["RightArm", "Torso"],
        ["LeftLeg", "Torso"],
        ["RightLeg", "Torso"]
    ]

    var actual_pairs = []
    for joint in pin_joints:
        var na = joint.node_a
        var nb = joint.node_b
        var body_a = root.get_node_or_null(na)
        var body_b = root.get_node_or_null(nb)
        if body_a == null:
            errors.append("PinJoint2D " + joint.name + " node_a path " + str(na) + " doesn't resolve")
        if body_b == null:
            errors.append("PinJoint2D " + joint.name + " node_b path " + str(nb) + " doesn't resolve")
        if body_a and body_b:
            actual_pairs.append([body_a.name, body_b.name])

    print("Actual PinJoint2D pairs:")
    for pair in actual_pairs:
        print("  " + pair[0] + " <-> " + pair[1])

    for exp_pair in expected_pairs:
        var found = false
        for act_pair in actual_pairs:
            var a1 = act_pair[0]
            var a2 = act_pair[1]
            var e1 = exp_pair[0]
            var e2 = exp_pair[1]
            if (a1 == e1 and a2 == e2) or (a1 == e2 and a2 == e1):
                found = true
                break
        if not found:
            errors.append("Missing PinJoint2D pair: " + exp_pair[0] + " <-> " + exp_pair[1])

    root.free()

    # Report
    if errors.size() == 0:
        print("ALL CHECKS PASSED")
        quit(0)
    else:
        for err in errors:
            printerr("FAIL: " + err)
        quit(1)
GDEOF

