extends SceneTree

func _initialize():
    var errors = []

    var packed = load("res://scenes/Ragdoll.tscn")
    var root = packed.instantiate()

    # Add to tree so NodePaths resolve properly
    get_root().add_child(root)

    var pin_joints = []
    var rb_names = []

    for child in root.get_children():
        if child is RigidBody2D:
            rb_names.append(child.name)
        elif child is PinJoint2D:
            pin_joints.append(child)

    print("RigidBody2D parts: " + str(rb_names))
    print("PinJoint2D count: " + str(pin_joints.size()))

    var actual_pairs = []
    for joint in pin_joints:
        var na = joint.node_a
        var nb = joint.node_b
        print("Joint " + joint.name + ": node_a=" + str(na) + " node_b=" + str(nb))

        # Try resolving relative to joint
        var body_a = joint.get_node_or_null(na)
        var body_b = joint.get_node_or_null(nb)

        print("  Resolved: " + str(body_a) + " <-> " + str(body_b))

        if body_a == null:
            errors.append("node_a doesn't resolve for " + joint.name + " path: " + str(na))
        if body_b == null:
            errors.append("node_b doesn't resolve for " + joint.name + " path: " + str(nb))
        if body_a and body_b:
            actual_pairs.append([body_a.name, body_b.name])

    print("Resolved pairs: " + str(actual_pairs))

    root.queue_free()

    if errors.size() == 0:
        print("ALL JOINT CHECKS PASSED")
    else:
        for e in errors:
            printerr("FAIL: " + e)

    quit(0 if errors.size() == 0 else 1)
