extends SceneTree

var ragdoll = null
var floor_body = null
var test_phase = 0
var frame_count = 0
var errors = []
var test_done = false
var impulse_applied = false
var collapse_signal_count = 0
var collapse_avg_pos = Vector2.ZERO
var pre_collapse_avg_pos = Vector2.ZERO

func _initialize():
    # Create a world with a floor
    var world = Node2D.new()
    world.name = "World"
    get_root().add_child(world)

    # Create the floor
    floor_body = StaticBody2D.new()
    floor_body.position = Vector2(0, 300)
    var floor_col = CollisionShape2D.new()
    var floor_shape = RectangleShape2D.new()
    floor_shape.size = Vector2(2000, 40)
    floor_col.shape = floor_shape
    floor_body.add_child(floor_col)
    world.add_child(floor_body)

    # Instantiate ragdoll above the floor
    var packed = load("res://scenes/Ragdoll.tscn")
    ragdoll = packed.instantiate()
    ragdoll.position = Vector2(0, 0)

    # Connect collapse signal
    ragdoll.ragdoll_collapsed.connect(_on_collapsed)

    world.add_child(ragdoll)

    print("Setup done, starting physics simulation...")
    print("Ragdoll class: " + ragdoll.get_class())
    print("Ragdoll script: " + str(ragdoll.get_script()))

func _on_collapsed(avg_pos: Vector2):
    collapse_signal_count += 1
    collapse_avg_pos = avg_pos
    pre_collapse_avg_pos = ragdoll.get_average_position()
    print("ragdoll_collapsed emitted! avg_pos=" + str(avg_pos) + " frame=" + str(frame_count))
    print("  get_average_position()=" + str(pre_collapse_avg_pos))

func _physics_process(_delta):
    if test_done:
        return

    frame_count += 1

    # Phase 1: After 1 physics frame, apply impulse and check velocity
    if frame_count == 1:
        # Test apply_impulse_to
        ragdoll.apply_impulse_to(&"Head", Vector2(0, -500))
        print("Phase 1: Applied impulse to Head")

    if frame_count == 2:
        var head = ragdoll.get_part(&"Head")
        if head == null:
            errors.append("get_part('Head') returned null")
        else:
            print("Head linear_velocity.y = " + str(head.linear_velocity.y))
            if head.linear_velocity.y >= -1.0:
                errors.append("After impulse, Head.linear_velocity.y should be < -1.0, got " + str(head.linear_velocity.y))
            else:
                print("PASS: Head velocity < -1.0 after impulse")

    # Phase 2: Test freeze_all
    if frame_count == 5:
        ragdoll.freeze_all(true)
        print("Phase 2: freeze_all(true)")
        var all_frozen = true
        for pname in [&"Head", &"Torso", &"LeftArm", &"RightArm", &"LeftLeg", &"RightLeg"]:
            var body = ragdoll.get_part(pname)
            if body and not body.freeze:
                all_frozen = false
                errors.append(str(pname) + ".freeze should be true after freeze_all(true)")
        if all_frozen:
            print("PASS: All bodies frozen")

        ragdoll.freeze_all(false)
        print("Phase 2: freeze_all(false)")
        var all_unfrozen = true
        for pname in [&"Head", &"Torso", &"LeftArm", &"RightArm", &"LeftLeg", &"RightLeg"]:
            var body = ragdoll.get_part(pname)
            if body and body.freeze:
                all_unfrozen = false
                errors.append(str(pname) + ".freeze should be false after freeze_all(false)")
        if all_unfrozen:
            print("PASS: All bodies unfrozen")

    # Phase 3: Simulate ~3 seconds (180 frames at 60fps = 3s)
    # Check collapse signal
    if frame_count > 180 * 5:  # 15 seconds max
        if collapse_signal_count == 0:
            errors.append("ragdoll_collapsed was never emitted after 15 seconds")
        elif collapse_signal_count > 1:
            errors.append("ragdoll_collapsed was emitted " + str(collapse_signal_count) + " times, expected 1")
        else:
            print("PASS: ragdoll_collapsed emitted exactly once")
            # Check centroid matches
            var dist = collapse_avg_pos.distance_to(pre_collapse_avg_pos)
            if dist > 0.01:
                errors.append("Emitted centroid doesn't match get_average_position() at that moment: dist=" + str(dist))
            else:
                print("PASS: Emitted centroid matches get_average_position()")

        test_done = true

        if errors.size() == 0:
            print("ALL PHYSICS TESTS PASSED")
            quit(0)
        else:
            for e in errors:
                printerr("FAIL: " + e)
            quit(1)

    if collapse_signal_count > 0 and frame_count > collapse_signal_count * 60 + 120:
        # We got the signal and waited 2 more seconds - check it wasn't emitted again
        if collapse_signal_count == 1:
            print("PASS: ragdoll_collapsed emitted exactly once (verified after extra time)")
            print("PASS: All runtime contracts verified")
            test_done = true
            quit(0)
GDEOF

